script:
frappe.ui.form.on("Salesperson Location Log", {
	refresh(frm) {
        if (frm.doc.latitude && frm.doc.longitude) {
            frm.add_custom_button(__('View on Google Maps'), () => {
                window.open(`https://www.google.com/maps?q=${frm.doc.latitude},${frm.doc.longitude}`, '_blank');
            }, 'Map');
        }
	}
});

frappe.ui.form.on("Customer Territory Map", {
	refresh(frm) {
        frm.get_field("map_view").$wrapper.html(`
            <div style="border: 1px solid #d1d8dd; border-radius: 4px; padding: 10px;">
                <h4 style="margin-top: 0;">Customer Global Map</h4>
                <div id="customer_leaflet_map" style="height: 500px; width: 100%; z-index: 1;"></div>
            </div>
        `);
        setTimeout(() => {
            frm.trigger('render_map');
        }, 300);
    },

    render_map(frm) {
        frappe.call({
            method: "sfa_crm.api.get_map_data", // <--- Updated to point to api.py
            callback: function(r) {
                let customers = r.message || [];
                let map_div = frm.get_field("map_view").$wrapper.find('#customer_leaflet_map')[0];
                if (!map_div) return;

                if (frm.map_instance) frm.map_instance.remove();

                let centerLat = -6.3690;
                let centerLng = 34.8888;
                if (customers.length > 0) {
                    centerLat = parseFloat(customers[0].custom_latitude);
                    centerLng = parseFloat(customers[0].custom_longitude);
                }

                frm.map_instance = L.map(map_div).setView([centerLat, centerLng], 6);
                L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
                    attribution: '© OpenStreetMap'
                }).addTo(frm.map_instance);

                customers.forEach(c => {
                    let lat = parseFloat(c.custom_latitude);
                    let lng = parseFloat(c.custom_longitude);
                    if (lat && lng) {
                        L.marker([lat, lng])
                            .addTo(frm.map_instance)
                            .bindPopup(`<b>${c.customer_name}</b><br>Territory: ${c.territory || 'N/A'}`);
                    }
                });
            }
        });
    }
});

frappe.ui.form.on("Salesperson Tracking Map", {
	refresh(frm) {
        frm.get_field("map_view").$wrapper.html(`
            <div style="border: 1px solid #d1d8dd; border-radius: 4px; padding: 10px;">
                <h4 style="margin-top: 0;">Salesperson Real-Time Location Map</h4>
                <div id="salesperson_leaflet_map" style="height: 600px; width: 100%; z-index: 1;"></div>
            </div>
        `);
        setTimeout(() => {
            frm.trigger('render_map');
        }, 300);
    },

    render_map(frm) {
        frappe.call({
            method: "frappe.client.get_list",
            args: {
                doctype: "Salesperson Location Log",
                fields: ["sales_person", "latitude", "longitude", "timestamp", "activity"],
                limit_page_length: 500,
                order_by: "timestamp desc"
            },
            callback: function(r) {
                let logs = r.message || [];
                let map_div = frm.get_field("map_view").$wrapper.find('#salesperson_leaflet_map')[0];
                if (!map_div) return;

                if (frm.map_instance) frm.map_instance.remove();

                let centerLat = -6.3690;
                let centerLng = 34.8888;
                if (logs.length > 0 && logs[0].latitude) {
                    centerLat = parseFloat(logs[0].latitude);
                    centerLng = parseFloat(logs[0].longitude);
                }

                frm.map_instance = L.map(map_div).setView([centerLat, centerLng], 12);
                L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', {
                    attribution: '© OpenStreetMap'
                }).addTo(frm.map_instance);

                logs.forEach(log => {
                    let lat = parseFloat(log.latitude);
                    let lng = parseFloat(log.longitude);
                    if (lat && lng) {
                        // Create a circle marker for tracking points
                        L.circleMarker([lat, lng], {
                            radius: 6,
                            fillColor: "#ff7800",
                            color: "#000",
                            weight: 1,
                            opacity: 1,
                            fillOpacity: 0.8
                        }).addTo(frm.map_instance)
                        .bindPopup(`<b>User:</b> ${log.sales_person}<br><b>Time:</b> ${log.timestamp}<br><b>Activity:</b> ${log.activity}`);
                    }
                });
            }
        });
    }
});

frappe.ui.form.on("Customer Territory Map", {
    refresh(frm) {
        frm.add_custom_button(__('Load Customer Map'), () => { frm.trigger('render_map'); });
    },
    render_map(frm) {
        frm.get_field("map_view").$wrapper.html(`
            <div style="padding: 10px; border: 1px solid #d1d8dd; border-radius: 6px; margin-top: 10px;">
                <h4 style="margin-top:0;">Customer Territory Map</h4>
                <div id="sfa_territory_map" style="height: 550px; width: 100%;"></div>
            </div>
        `);
        let map_div = frm.get_field("map_view").$wrapper.find('#sfa_territory_map')[0];
        frappe.call({
            method: "sfa_crm.api.get_map_data",
            callback: function(r) {
                let customers = r.message || [];
                if (frm.territory_map) frm.territory_map.remove();
                let centerLat = -6.3690, centerLng = 34.8888;
                if (customers.length > 0) { centerLat = parseFloat(customers[0].custom_latitude); centerLng = parseFloat(customers[0].custom_longitude); }
                frm.territory_map = L.map(map_div).setView([centerLat, centerLng], 8);
                L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', { attribution: '© OpenStreetMap' }).addTo(frm.territory_map);
                customers.forEach(c => {
                    let lat = parseFloat(c.custom_latitude), lng = parseFloat(c.custom_longitude);
                    if (lat && lng) L.marker([lat, lng]).addTo(frm.territory_map).bindPopup(`<b>${c.customer_name}</b><br>Territory: ${c.territory || 'N/A'}`);
                });
                if (customers.length === 0) frappe.msgprint("No customers with GPS coordinates found.");
            }
        });
    }
});

frappe.ui.form.on('Sales Team Tracker', {
    refresh: function(frm) {
        frm.disable_save();

        frm.get_field('map_html').$wrapper.html(`
            <div style="background: #f8f9fa; padding: 20px; border-radius: 8px; border: 1px solid #ddd; margin-bottom: 15px;">
                <div class="row">
                    <div class="col-md-3">
                        <label>Start Date</label>
                        <input type="date" id="map-start-date" class="form-control input-sm" value="${frappe.datetime.get_today()}">
                    </div>
                    <div class="col-md-3">
                        <label>End Date</label>
                        <input type="date" id="map-end-date" class="form-control input-sm" value="${frappe.datetime.get_today()}">
                    </div>
                    <div class="col-md-3">
                        <label>Salesperson Filter</label>
                        <select id="map-person" class="form-control input-sm">
                            <option value="All">All Staff</option>
                        </select>
                    </div>
                    <div class="col-md-3" style="margin-top: 24px;">
                        <button class="btn btn-primary btn-sm" id="btn-refresh-map">Fetch Data</button>
<button class="btn btn-success btn-sm" id="btn-replay-route" style="margin-left: 10px;">▶ Replay</button>
<button class="btn btn-warning btn-sm" id="btn-pause-replay" style="margin-left: 5px;">⏸ Pause</button>
                    </div>
                </div>
            </div>
            <div id="map-status" style="margin-bottom: 10px; font-weight: bold; color: #1976D2;">Initializing Map Engine...</div>
            <div id="salesMap" style="height: 700px; width: 100%; border-radius: 8px; border: 2px solid #ccc; z-index: 1;"></div>
        `);

        if (!$('link[href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css"]').length) {
            $('head').append('<link rel="stylesheet" href="https://unpkg.com/leaflet@1.9.4/dist/leaflet.css" type="text/css" />');
        }
        frappe.require("https://unpkg.com/leaflet@1.9.4/dist/leaflet.js", function() { init_advanced_map(frm); });
    }
});

function init_advanced_map(frm) {
    let map = L.map('salesMap').setView([-6.8, 39.2], 12); 
    L.tileLayer('https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png', { attribution: '© OpenStreetMap' }).addTo(map);
    let markersLayer = new L.FeatureGroup().addTo(map);

    window.currentPaths = {}; 
    let replayTimer = null;

    // PRE-FETCH ALL USERS FOR THE DROPDOWN
    frappe.call({
        method: 'frappe.client.get_list',
        args: { doctype: 'User', fields: ['full_name'], filters: [['enabled', '=', 1]], limit_page_length: 500 },
        callback: function(r) {
            if (r.message) {
                let dropdown = document.getElementById('map-person');
                r.message.forEach(u => {
                    let opt = document.createElement("option");
                    opt.value = u.full_name;
                    opt.text = u.full_name;
                    dropdown.add(opt);
                });
            }
        }
    });

    function fetch_locations() {
        if(replayTimer) clearInterval(replayTimer);
        document.getElementById('map-status').innerText = "Querying Server Database...";
        markersLayer.clearLayers();

        // Must append exact times to bypass strict dateutil parsers in Frappe v15
        let startDate = document.getElementById('map-start-date').value + " 00:00:00";
        let endDate = document.getElementById('map-end-date').value + " 23:59:59";
        let selectedPerson = document.getElementById('map-person').value;

        let filters = [['timestamp', 'between', [startDate, endDate]]];
        if (selectedPerson !== "All") filters.push(['sales_person', '=', selectedPerson]);

        frappe.call({
            method: 'frappe.client.get_list',
            args: {
                doctype: 'Salesperson Location Log',
                fields: ['sales_person', 'latitude', 'longitude', 'timestamp', 'activity'],
                filters: filters,
                limit_page_length: 10000,
                order_by: 'timestamp asc'
            },
            callback: function(r) {
                if (r.message && r.message.length > 0) {
                    window.currentPaths = {};

                    r.message.forEach(log => {
                        if (!window.currentPaths[log.sales_person]) window.currentPaths[log.sales_person] = [];
                        let lat = parseFloat(log.latitude);
                        let lng = parseFloat(log.longitude);

                        if (!isNaN(lat) && !isNaN(lng)) {
                            let pathArr = window.currentPaths[log.sales_person];
                            if (pathArr.length === 0) {
                                pathArr.push({ lat, lng, time: log.timestamp, activity: log.activity });
                            } else {
                                // Anti-Drift: Only store if moved > 25 meters
                                let lastPt = pathArr[pathArr.length - 1];
                                let dist = L.latLng(lastPt.lat, lastPt.lng).distanceTo(L.latLng(lat, lng));
                                if (dist > 25) pathArr.push({ lat, lng, time: log.timestamp, activity: 'Moving' });
                                else { lastPt.time = log.timestamp; lastPt.activity = 'Stationary'; }
                            }
                        }
                    });

                    render_static_map();

                } else {
                    document.getElementById('map-status').innerText = `No GPS data found in this date range.`;
                    window.currentPaths = {};
                }
            }
        });
    }

    function render_static_map() {
        markersLayer.clearLayers();
        let bounds = [];

        Object.keys(window.currentPaths).forEach(person => {
            let pathData = window.currentPaths[person];
            if(pathData.length === 0) return;

            let latlngs = pathData.map(p => [p.lat, p.lng]);
            L.polyline(latlngs, {color: '#D32F2F', weight: 4, opacity: 0.8}).addTo(markersLayer); 

            pathData.forEach(p => {
                L.circleMarker([p.lat, p.lng], { radius: 4, color: 'black', fillColor: 'white', fillOpacity: 1 }).addTo(markersLayer);
                bounds.push([p.lat, p.lng]);
            });

            let lastPoint = pathData[pathData.length - 1];
            let iconUrl = lastPoint.activity === 'Moving' ? '🟢' : '🔴';

            let marker = L.marker([lastPoint.lat, lastPoint.lng]).bindPopup(`
                <b>🧑‍💼 ${person}</b><br>
                ⏱️ Last Seen: ${lastPoint.time}<br>
                🏃 Status: ${iconUrl} ${lastPoint.activity}
            `).addTo(markersLayer);
            marker.openPopup();
        });

        if (bounds.length > 0) map.fitBounds(bounds, { padding: [50, 50] });
        document.getElementById('map-status').innerText = `Showing optimized routes for ${Object.keys(window.currentPaths).length} rep(s).`;
    }

    document.getElementById('btn-replay-route').addEventListener('click', function() {
        let keys = Object.keys(window.currentPaths);
        if(keys.length === 0) return;

        markersLayer.clearLayers();
        document.getElementById('map-status').innerText = "▶ Replaying Historical Route...";

        let playbackMarkers = {};
        let index = 0;
        let maxLength = Math.max(...keys.map(k => window.currentPaths[k].length));

        keys.forEach(p => {
            let firstPt = window.currentPaths[p][0];
            playbackMarkers[p] = {
                marker: L.marker([firstPt.lat, firstPt.lng]).addTo(markersLayer),
                line: L.polyline([[firstPt.lat, firstPt.lng]], {color: '#1976D2', weight: 5}).addTo(markersLayer)
            };
            playbackMarkers[p].marker.bindTooltip(`<b>${p}</b><br>${firstPt.time}`).openTooltip();
        });

        replayTimer = setInterval(() => {
            index++;
            if (index >= maxLength) {
                clearInterval(replayTimer);
                document.getElementById('map-status').innerText = "✅ Route Replay Complete.";
                return;
            }

            keys.forEach(p => {
                let pathArr = window.currentPaths[p];
                if (index < pathArr.length) {
                    let pt = pathArr[index];
                    let latlng = [pt.lat, pt.lng];
                    playbackMarkers[p].marker.setLatLng(latlng);
                    playbackMarkers[p].marker.setTooltipContent(`<b>${p}</b><br>${pt.time}`);
                    playbackMarkers[p].line.addLatLng(latlng);
                }
            });
        }, 500); 
    });

    document.getElementById('btn-refresh-map').addEventListener('click', fetch_locations);
    fetch_locations();
}
